SENSITIVE_ATTRS = {"api_key", "authorization", "x-api-key", "api_base", "password", "secret"}

def _sanitize(obj, _seen=None):
    if _seen is None:
        _seen = set()
    if isinstance(obj, dict):
        return {
            k: ("***REDACTED***" if k.lower() in SENSITIVE_ATTRS else _sanitize(v, _seen))
            for k, v in obj.items()
        }
    if isinstance(obj, list):
        return [_sanitize(i, _seen) for i in obj]
    if hasattr(obj, "__dict__"):
        oid = id(obj)
        if oid in _seen:
            return "<recursion>"
        _seen.add(oid)
        return _sanitize(obj.__dict__, _seen)
    return obj

