        content = msg.get("content")
        if isinstance(content, list):
            parts = []
            for block in content:
                if not isinstance(block, dict):
                    continue
                t = block.get("type")
                if t == "text":
                    parts.append(block.get("text", ""))
                elif t == "tool_result":
                    parts.append(f"[Tool Result ID: {block.get('tool_use_id', 'unknown')}]")
                    parts.append(_flatten_tool_result_content(block.get("content")))
                elif t == "tool_use":
                    parts.append(f"[Tool: {block.get('name')} (ID: {block.get('id')})]\nInput: {json.dumps(block.get('input', {}))}")
                elif t == "image":
                    parts.append("[Image content]")
            text_content = "\n".join(parts).strip() or "..."
            out.append({"role": msg["role"], "content": text_content})
        else:
            out.append({k: v for k, v in msg.items() if k in _OPENAI_SENTINEL_KEYS})
    return out

